const {
  findPriceReceivedEvent,
  hasPrice,
  normalizePrice,
  pricesDiffer,
} = require('../../helpers/rfq-quote-date-backfill');

describe('rfq quote date backfill helper', () => {
  test('normalizes empty and numeric prices', () => {
    expect(hasPrice(null)).toBe(false);
    expect(hasPrice('')).toBe(false);
    expect(normalizePrice('$1,200.00')).toBe('1200');
    expect(pricesDiffer('12.0', '12')).toBe(false);
  });

  test('finds first audit row where matching quote price is populated', () => {
    const decision = findPriceReceivedEvent(
      { quoteId: 10, price: '8.50' },
      [
        {
          id: 1,
          actionDate: '2026-01-01T10:00:00Z',
          oldValue: JSON.stringify({ RFQVendor_id: 10, RFQVendor_amount: null }),
          newValue: JSON.stringify({ RFQVendor_id: 10, RFQVendor_amount: null }),
        },
        {
          id: 2,
          actionDate: '2026-01-02T10:00:00Z',
          username: 'Factory User',
          oldValue: JSON.stringify({ RFQVendor_id: 10, RFQVendor_amount: null }),
          newValue: JSON.stringify({ RFQVendor_id: 10, RFQVendor_amount: '8.50' }),
        },
      ]
    );

    expect(decision.status).toBe('exact');
    expect(decision.quoteDate).toBe('2026-01-02');
    expect(decision.auditLogId).toBe(2);
    expect(decision.reason).toBe('price_first_populated');
  });

  test('does not mix audit rows from another quote on the same rfq item', () => {
    const decision = findPriceReceivedEvent(
      { quoteId: 10, price: '8.50' },
      [
        {
          id: 1,
          actionDate: '2026-01-01T10:00:00Z',
          oldValue: JSON.stringify({ RFQVendor_id: 11, RFQVendor_amount: null }),
          newValue: JSON.stringify({ RFQVendor_id: 11, RFQVendor_amount: '7.00' }),
        },
      ]
    );

    expect(decision.status).toBe('unrecoverable');
    expect(decision.reason).toBe('no_quote_audit_rows');
  });

  test('reports approximate fallback from factory sent date but does not call it exact', () => {
    const decision = findPriceReceivedEvent(
      {
        quoteId: 10,
        price: '8.50',
        factorySentDate: '2026-02-03T15:00:00Z',
      },
      []
    );

    expect(decision.status).toBe('approximate');
    expect(decision.quoteDate).toBe('2026-02-03');
  });
});

