    // cost basis (mddp) = 4.00 (fob 4, agent 0, duty 0, dutyDollar 0)
    // royalty 12, dilution 5, logistics 3, target 8 → deduction 0.80 → net 6.40
    // margin = (6.40 - 4.00) / 8.00 * 100 = 30
    const colHeaders = headersFor([...baseColIds, 'lic_mddp_buyer_target', 'lic_mddp_buyer_margin']);
    const params = makeParams({
      fob_cost: 4, agent: 0, duty_rate: { title: 0 }, duty_rate_dollar_amount: 0,
      logistics_load: 3, dilution: 5, lic_mddp_royalty: 12,
      lic_mddp_buyer_target: 8,
