import { describe, expect, it } from '@jest/globals';
import { TrackingService } from './tracking.service';

describe('TrackingService auth headers', () => {
  it('does not set Authorization when token is missing', () => {
    localStorage.removeItem('token');
    const service = new TrackingService({} as any);

    const headers = service.setUserAuth();

    expect(headers.has('Authorization')).toBe(false);
  });

  it('does not set Authorization in loader headers when token is missing', () => {
    localStorage.removeItem('token');
    const service = new TrackingService({} as any);

    const headers = service.setUserAuthWithLoader();

    expect(headers.has('Authorization')).toBe(false);
    expect(headers.get('X-Enable-Loader')).toBe('true');
  });
});

