const { describe, test, expect, beforeEach, afterEach, jest } = require('@jest/globals');

describe('auth helper JWT verification', () => {
  beforeEach(() => {
    jest.resetModules();
    process.env.JWT_PUBLIC_KEY = 'public-key';
  });

  afterEach(() => {
    jest.dontMock('jsonwebtoken');
  });

  test('pins verification to RS256 using jsonwebtoken algorithms option', () => {
    const verify = jest.fn().mockReturnValue({ role: 'admin' });
    jest.doMock('jsonwebtoken', () => ({ verify }));

    const { authToken } = require('../../helpers/auth');
    const ok = authToken({ headers: { authorization: 'token' } });

    expect(ok).toBe(true);
    expect(verify).toHaveBeenCalledWith('token', 'public-key', { algorithms: ['RS256'] });
  });
});

const { describe, test, expect, beforeEach, afterEach, jest } = require('@jest/globals');

jest.mock('../../models/db', () => ({
  Factory: { findOne: jest.fn() },
  vendor: { findOne: jest.fn(), findAll: jest.fn(), update: jest.fn() },
  RFQItem: { findOne: jest.fn(), destroy: jest.fn() },
  RFQVendor: { findOne: jest.fn(), findAll: jest.fn(), create: jest.fn(), findOrCreate: jest.fn(), update: jest.fn() },
  users: { findOne: jest.fn(), update: jest.fn() },
  auth_token: { update: jest.fn() },
}));

jest.mock('../../helpers/utility', () => ({
  mapRFQItem: jest.fn(),
  cryptPassword: jest.fn(),
}));

jest.mock('../../helpers/auth', () => ({
  authToken: jest.fn(),
  getUserInfo: jest.fn(),
}));

jest.mock('node-fetch', () => jest.fn());
jest.mock('../../services/std.service', () => ({}));
jest.mock('../../services/email.service', () => ({}));
jest.mock('../../helpers/brevo', () => ({}));
jest.mock('../../helpers/rfqHistory', () => ({}));
jest.mock('../../helpers/rfqCopyMerchGroupGuard', () => ({}));
jest.mock('dotenv', () => ({ config: jest.fn() }));

const sql = require('../../models/db');
const utility = require('../../helpers/utility');
const { getUserInfo } = require('../../helpers/auth');
const Customer = require('../../models/lib.model');

describe('Customer legacy callback error handling', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    jest.spyOn(console, 'error').mockImplementation(() => {});
  });

  afterEach(() => {
    console.error.mockRestore();
  });

  test('reqVendor reports database failures in the error callback slot', async () => {
    sql.Factory.findOne.mockRejectedValue(new Error('database offline'));

    const result = jest.fn();
    await Customer.reqVendor({ body: { rfqItem_priceCode: 'RFQ-1', id: 10 } }, result);

    expect(result).toHaveBeenCalledTimes(1);
    expect(result.mock.calls[0][0]).toBeInstanceOf(Error);
    expect(result.mock.calls[0][0].message).toBe('Failed to request vendor quote.');
    expect(result.mock.calls[0][1]).toBeNull();
  });

  test('deleteRFQItem reports a zero-row delete instead of hanging', async () => {
    utility.mapRFQItem.mockResolvedValue({ rfqItem_style_number: 'RFQ-MISSING' });
    sql.RFQItem.destroy.mockResolvedValue(0);

    const result = jest.fn();
    await Customer.deleteRFQItem({ body: { data: { 'Price Code': 'RFQ-MISSING' } } }, result);

    expect(result).toHaveBeenCalledTimes(1);
    expect(result.mock.calls[0][0]).toBeInstanceOf(Error);
    expect(result.mock.calls[0][0].message).toContain('RFQ item not found');
    expect(result.mock.calls[0][1]).toBeNull();
  });

  test('changePassword returns a clean invalid-link error for bad reset tokens', async () => {
    getUserInfo.mockResolvedValue(null);

    const result = jest.fn();
    await Customer.changePassword({ body: { token: 'expired', password: '[REDACTED]' } }, result);

    expect(result).toHaveBeenCalledTimes(1);
    expect(result.mock.calls[0][0]).toBeInstanceOf(Error);
    expect(result.mock.calls[0][0].message).toBe('Password reset link is expired or invalid.');
    expect(result.mock.calls[0][1]).toBeNull();
    expect(utility.cryptPassword).not.toHaveBeenCalled();
  });
});

